/**
 * Generate placeholder invoice number (PI/MM/YY/001 format)
 * Actual number auto-generated by backend on save
 */
export const generateInvoiceNumber = () => {
  return `[AUTO]`;
};

/**
 * Generate unique order number with proper formatting
 */
export const generateOrderNumber = () => {
  const now = new Date();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const year = String(now.getFullYear()).slice(-2);
  const ts = String(Date.now()).slice(-4);
  return `PO/${month}/${year}/${ts}`;
};

